	$email = isset($user['email']) ? esc_html($user['email']) : '';
	$first_name = isset($user['first_name']) ? esc_html($user['first_name']) : '';
	$last_name = isset($user['last_name']) ? esc_html($user['last_name']) : '';
	$membership_level = isset($user['membership_level']) ? esc_html($user['membership_level']) : '';
	$created_at = isset($user['created_at']) ? esc_html($user['created_at']) : '';

	$full_name = trim($first_name . ' ' . $last_name);
